                dir = dir.getParentFile();
            }

            while (true) {
                if (dir == null || dir.isDirectory()) break;
                if (!dir.exists()) {
                    dir = dir.getParentFile();
                }
            }

            if (textFieldPath.getText().isEmpty() || !dir.exists() || !dir.isDirectory()) {
                directoryChooser.setInitialDirectory(new File(System.getProperty("user.home")));
